#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.keybinding)]
    public class KeybindingOptionButton : OptionButtonDefinition
    {
        public KeybindingOptionButton(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return !Global.Game.IsMobile();
        }
        public override void OnClick()
        {
            Global.Scene.OpenKeybindingPanel();
        }
    }
}
